import {normalizedArticles} from '../fixtures'
import {DELETE_ARTICLE} from '../types'

export default function (articles = normalizedArticles, action) {
    switch (action.type) {
        case DELETE_ARTICLE:
            return articles.filter(article => article.id !== action.payload.id)
        default:
            return articles
    }
}
